-- =============================================================
-- CD Catalogue — Supabase schema + seed data
-- User: auth0|69e8ae41a70a7624924b40c7
-- =============================================================

-- ── 1. TABLES ─────────────────────────────────────────────────

-- Owned top albums
CREATE TABLE IF NOT EXISTS cd_albums (
  id             BIGSERIAL PRIMARY KEY,
  user_id        TEXT      NOT NULL,
  seq_num        INTEGER,
  release_date   DATE,
  artist         TEXT      NOT NULL,
  year           INTEGER,
  title          TEXT      NOT NULL,
  publisher      TEXT,
  allmusic_rating NUMERIC(3,1),
  album_pick     BOOLEAN   DEFAULT FALSE,
  is_5star       BOOLEAN   DEFAULT FALSE,
  is_4half_star  BOOLEAN   DEFAULT FALSE,
  rs_tier        TEXT      CHECK (rs_tier IN ('top-50','51-100','101-250','251-500')),
  rs_top500      BOOLEAN,
  notes          TEXT,
  tags           TEXT[]    DEFAULT '{}',
  created_at     TIMESTAMPTZ DEFAULT now(),
  updated_at     TIMESTAMPTZ DEFAULT now()
);

-- Compilations
CREATE TABLE IF NOT EXISTS cd_compilations (
  id             BIGSERIAL PRIMARY KEY,
  user_id        TEXT      NOT NULL,
  seq_num        INTEGER,
  release_date   DATE,
  artist         TEXT      NOT NULL,
  year           INTEGER,
  title          TEXT      NOT NULL,
  publisher      TEXT,
  allmusic_rating NUMERIC(3,1),
  album_pick     BOOLEAN   DEFAULT FALSE,
  is_5star       BOOLEAN   DEFAULT FALSE,
  is_4half_star  BOOLEAN   DEFAULT FALSE,
  notes          TEXT,
  tags           TEXT[]    DEFAULT '{}',
  created_at     TIMESTAMPTZ DEFAULT now(),
  updated_at     TIMESTAMPTZ DEFAULT now()
);

-- Wishlist (albums to acquire)
CREATE TABLE IF NOT EXISTS cd_wishlist (
  id             BIGSERIAL PRIMARY KEY,
  user_id        TEXT      NOT NULL,
  release_date   DATE,
  artist         TEXT      NOT NULL,
  year           INTEGER,
  title          TEXT      NOT NULL,
  publisher      TEXT,
  allmusic_rating NUMERIC(3,1),
  album_pick     BOOLEAN   DEFAULT FALSE,
  is_5star       BOOLEAN   DEFAULT FALSE,
  is_4half_star  BOOLEAN   DEFAULT FALSE,
  is_4star       BOOLEAN   DEFAULT FALSE,
  rs_tier        TEXT      CHECK (rs_tier IN ('top-50','51-100','101-250','251-500')),
  rs_top500      BOOLEAN,
  notes          TEXT,
  tags           TEXT[]    DEFAULT '{}',
  created_at     TIMESTAMPTZ DEFAULT now(),
  updated_at     TIMESTAMPTZ DEFAULT now()
);

-- Rolling Stone 500 Greatest Albums — 2012 edition
CREATE TABLE IF NOT EXISTS cd_rs_2012 (
  id         BIGSERIAL PRIMARY KEY,
  user_id    TEXT    NOT NULL,
  rs_rank    INTEGER NOT NULL,
  entry_text TEXT    NOT NULL,
  owned      BOOLEAN DEFAULT FALSE,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- Rolling Stone 500 Greatest Albums — 2020 edition
CREATE TABLE IF NOT EXISTS cd_rs_2020 (
  id         BIGSERIAL PRIMARY KEY,
  user_id    TEXT    NOT NULL,
  rs_rank    INTEGER NOT NULL,
  entry_text TEXT    NOT NULL,
  owned      BOOLEAN DEFAULT FALSE,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- ── 2. INDEXES ────────────────────────────────────────────────

CREATE INDEX IF NOT EXISTS cd_albums_user_id       ON cd_albums       (user_id);
CREATE INDEX IF NOT EXISTS cd_compilations_user_id ON cd_compilations  (user_id);
CREATE INDEX IF NOT EXISTS cd_wishlist_user_id     ON cd_wishlist      (user_id);
CREATE INDEX IF NOT EXISTS cd_rs_2012_user_id      ON cd_rs_2012       (user_id);
CREATE INDEX IF NOT EXISTS cd_rs_2020_user_id      ON cd_rs_2020       (user_id);

-- ── 3. ROW-LEVEL SECURITY ─────────────────────────────────────

ALTER TABLE cd_albums       ENABLE ROW LEVEL SECURITY;
ALTER TABLE cd_compilations ENABLE ROW LEVEL SECURITY;
ALTER TABLE cd_wishlist     ENABLE ROW LEVEL SECURITY;
ALTER TABLE cd_rs_2012      ENABLE ROW LEVEL SECURITY;
ALTER TABLE cd_rs_2020      ENABLE ROW LEVEL SECURITY;

-- Owner can read/write their own rows (matches existing user_app_state policy pattern)
CREATE POLICY cd_albums_select       ON cd_albums       FOR SELECT USING     ((auth.jwt() ->> 'sub'::text) = user_id);
CREATE POLICY cd_albums_insert       ON cd_albums       FOR INSERT WITH CHECK ((auth.jwt() ->> 'sub'::text) = user_id);
CREATE POLICY cd_albums_update       ON cd_albums       FOR UPDATE USING     ((auth.jwt() ->> 'sub'::text) = user_id) WITH CHECK ((auth.jwt() ->> 'sub'::text) = user_id);
CREATE POLICY cd_albums_delete       ON cd_albums       FOR DELETE USING     ((auth.jwt() ->> 'sub'::text) = user_id);

CREATE POLICY cd_compilations_select ON cd_compilations FOR SELECT USING     ((auth.jwt() ->> 'sub'::text) = user_id);
CREATE POLICY cd_compilations_insert ON cd_compilations FOR INSERT WITH CHECK ((auth.jwt() ->> 'sub'::text) = user_id);
CREATE POLICY cd_compilations_update ON cd_compilations FOR UPDATE USING     ((auth.jwt() ->> 'sub'::text) = user_id) WITH CHECK ((auth.jwt() ->> 'sub'::text) = user_id);
CREATE POLICY cd_compilations_delete ON cd_compilations FOR DELETE USING     ((auth.jwt() ->> 'sub'::text) = user_id);

CREATE POLICY cd_wishlist_select     ON cd_wishlist     FOR SELECT USING     ((auth.jwt() ->> 'sub'::text) = user_id);
CREATE POLICY cd_wishlist_insert     ON cd_wishlist     FOR INSERT WITH CHECK ((auth.jwt() ->> 'sub'::text) = user_id);
CREATE POLICY cd_wishlist_update     ON cd_wishlist     FOR UPDATE USING     ((auth.jwt() ->> 'sub'::text) = user_id) WITH CHECK ((auth.jwt() ->> 'sub'::text) = user_id);
CREATE POLICY cd_wishlist_delete     ON cd_wishlist     FOR DELETE USING     ((auth.jwt() ->> 'sub'::text) = user_id);

CREATE POLICY cd_rs_2012_select      ON cd_rs_2012      FOR SELECT USING     ((auth.jwt() ->> 'sub'::text) = user_id);
CREATE POLICY cd_rs_2012_insert      ON cd_rs_2012      FOR INSERT WITH CHECK ((auth.jwt() ->> 'sub'::text) = user_id);
CREATE POLICY cd_rs_2012_update      ON cd_rs_2012      FOR UPDATE USING     ((auth.jwt() ->> 'sub'::text) = user_id) WITH CHECK ((auth.jwt() ->> 'sub'::text) = user_id);
CREATE POLICY cd_rs_2012_delete      ON cd_rs_2012      FOR DELETE USING     ((auth.jwt() ->> 'sub'::text) = user_id);

CREATE POLICY cd_rs_2020_select      ON cd_rs_2020      FOR SELECT USING     ((auth.jwt() ->> 'sub'::text) = user_id);
CREATE POLICY cd_rs_2020_insert      ON cd_rs_2020      FOR INSERT WITH CHECK ((auth.jwt() ->> 'sub'::text) = user_id);
CREATE POLICY cd_rs_2020_update      ON cd_rs_2020      FOR UPDATE USING     ((auth.jwt() ->> 'sub'::text) = user_id) WITH CHECK ((auth.jwt() ->> 'sub'::text) = user_id);
CREATE POLICY cd_rs_2020_delete      ON cd_rs_2020      FOR DELETE USING     ((auth.jwt() ->> 'sub'::text) = user_id);

