-- ── 5. STRIP RANK PREFIX FROM RS ENTRY_TEXT ─────────────────
-- (entry_text was inserted as "N. Artist, Title"; rank is already in rs_rank)
UPDATE cd_rs_2012
SET entry_text = regexp_replace(entry_text, '^\d+\.\s*', '')
WHERE user_id = 'auth0|69e8ae41a70a7624924b40c7'
  AND entry_text ~ '^\d+\.';

UPDATE cd_rs_2020
SET entry_text = regexp_replace(entry_text, '^\d+\.\s*', '')
WHERE user_id = 'auth0|69e8ae41a70a7624924b40c7'
  AND entry_text ~ '^\d+\.';

-- ── 6. ENABLE MUSIC COLLECTION FOR USER ──────────────────────
UPDATE profiles
SET enabled_collections = array_append(enabled_collections, 'music')
WHERE auth0_id = 'auth0|69e8ae41a70a7624924b40c7'
  AND NOT ('music' = ANY(enabled_collections));